189	uint64_t bitstream_member_offset(const ast::FieldSymbol &member)
190	{
191		const ast::Symbol &parent = member.getParentScope()->asSymbol();
192		ast_invariant(member, ast::Type::isKind(parent.kind));
193	
194		uint64_t bit_offset = member.bitOffset;
195		
196		const ast::Type &symbol = parent.as<ast::Type>();	
197		// Slang stores `FieldSymbol::bitOffset` MSB-first inside unpacked structs, while
198		// Yosys works with bitstream-serialization order (LSB-first). This helper
199		// mirrors Slang's offset so every caller sees the physical bit index actually
200		// used when flattening into a bitstream.
201		if (symbol.isUnpackedStruct()) {
202			const auto &unpacked = symbol.as<ast::UnpackedStructType>();
203			ast_invariant(member, unpacked.bitstreamWidth == unpacked.selectableWidth);
204			bit_offset = unpacked.bitstreamWidth - member.bitOffset
205					 - member.getType().getBitstreamWidth();
206		}
207		return bit_offset;
208	}
