220	static const RTLIL::Const convert_svint(const slang::SVInt &svint)
221	{
222		std::vector<RTLIL::State> bits;
223		bits.reserve(svint.getBitWidth());
224		for (int i = 0; i < (int) svint.getBitWidth(); i++)
225		switch (svint[i].value) {
226		case 0: bits.push_back(RTLIL::State::S0); break;
227		case 1: bits.push_back(RTLIL::State::S1); break;
228		case slang::logic_t::X_VALUE: bits.push_back(RTLIL::State::Sx); break;
229		case slang::logic_t::Z_VALUE: bits.push_back(RTLIL::State::Sz); break;
230		}
231		return bits;
232	}
