234	const std::optional<RTLIL::Const> NetlistContext::convert_const(const slang::ConstantValue &constval,
235																	slang::SourceLocation loc)
236	{
237		if (constval.bad()) {
238			// no diagnostic in this case as we assume one has been raised upstream
239			return {};
240		} else if (constval.isReal()) {
241			add_diag(diag::UnsupportedBitConversion, loc) << "real"sv;
242			return {};
243		} else if (constval.isShortReal()) {
244			add_diag(diag::UnsupportedBitConversion, loc) << "shortreal"sv;
245			return {};
246		} else if (constval.isUnbounded()) {
247			add_diag(diag::UnsupportedBitConversion, loc) << "unbounded symbol"sv;
248			return {};
249		} else if (constval.isMap()) {
250			add_diag(diag::UnsupportedBitConversion, loc) << "map"sv;
251			return {};
252		} else if (constval.isQueue()) {
253			add_diag(diag::UnsupportedBitConversion, loc) << "queue"sv;
254			return {};
255		} else if (constval.isUnion()) {
256			add_diag(diag::UnsupportedBitConversion, loc) << "union"sv;
257			return {};
258		}
259	
260		if (constval.isInteger()) {
261			return convert_svint(constval.integer());
262		} else if (constval.isUnpacked()) {
263			std::vector<RTLIL::State> bits;
264			bits.reserve(constval.getBitstreamWidth());
265	
266			auto elems = constval.elements();
267			for (auto it = elems.rbegin(); it != elems.rend(); it++) {
268				if (auto piece = convert_const(*it, loc)) {
269					bits.insert(bits.end(), piece->begin(), piece->end());	
270				} else {
271					return {};
272				}
273			}
274	
275			log_assert(bits.size() == constval.getBitstreamWidth());
276			return bits;
277		} else if (constval.isString()) {
278			RTLIL::Const ret = convert_svint(constval.convertToInt().integer());
279			ret.flags |= RTLIL::CONST_FLAG_STRING;
280			return ret;
281		} else if (constval.isNullHandle()) {
282			return {};
283		}
284	
285		log_abort();
286	}
