288	std::optional<RTLIL::Const> convert_attr_value(NetlistContext &netlist, const ast::AttributeSymbol* symbol)
289	{
290		auto value = netlist.convert_const(symbol->getValue(), symbol->location);
291		if (value) {
292			// slang converts string literals to integer constants per the spec;
293			// we need to look at the syntax tree to recover the information
294			if (symbol->getSyntax() &&
295				symbol->getSyntax()->kind == syntax::SyntaxKind::AttributeSpec &&
296				symbol->getSyntax()->template as<syntax::AttributeSpecSyntax>().value &&
297				symbol->getSyntax()->template as<syntax::AttributeSpecSyntax>().value->expr->kind ==
298					syntax::SyntaxKind::StringLiteralExpression) {
299				value->flags |= RTLIL::CONST_FLAG_STRING;
300			}
301		}
302		return value;
303	}
