310			to->attributes[ID::src] = src;
311	
312		for (auto attr : global_compilation->getAttributes(from)) {
313			if (auto value = convert_attr_value(netlist, attr)) {
314				to->attributes[id(attr->name)] = *value;
315			}
316		}
