340	static Yosys::pool<VariableBit> detect_possibly_unassigned_subset(Yosys::pool<VariableBit> &signals, Case *rule, int level=0)
341	{
342		Yosys::pool<VariableBit> remaining = signals;
343		bool debug = false;
344	
345		for (auto &action : rule->actions) {
346			if (debug) {
347				log_debug("%saction %s<=%s (mask %s)\n", std::string(level, ' ').c_str(),
348						  "FIXME" /* log_signal(action.lvalue) */, log_signal(action.unmasked_rvalue), log_signal(action.mask));
349			}
350	
351			if (action.mask.is_fully_ones())
352			for (auto bit : action.lvalue)
353				remaining.erase(bit);
354		}
355	
356		for (auto switch_ : rule->switches) {
357			if (debug) {
358				log_debug("%sswitch %s\n", std::string(level, ' ').c_str(), log_signal(switch_->signal));
359			}
360	
361			if (remaining.empty())
362				break;
363	
364			Yosys::pool<VariableBit> new_remaining;
365			Yosys::BitPatternPool pool(switch_->signal);
366			for (auto case_ : switch_->cases) {
367				if (!switch_->signal.empty() && pool.empty())
368					break;
369	
370				if (debug) {
371					log_debug("%s case ", std::string(level, ' ').c_str());
372					for (auto compare : case_->compare)
373						log_debug("%s ", log_signal(compare));
374					log_debug("\n");
375				}
376	
377				bool selectable = false;
378				if (case_->compare.empty()) {
379					// we have reached a default, by now we know this case is full
380					selectable = pool.take_all() || switch_->signal.empty();
381				} else {
382					for (auto compare : case_->compare) {
383						if (!compare.is_fully_const()) {
384							if (!pool.empty())
385								selectable = true;
386						} else {
387							if (pool.take(compare))
388								selectable = true;
389						}
390					}
391				}
392	
393				if (selectable) {
394					for (auto bit : detect_possibly_unassigned_subset(remaining, case_, level + 2))
395						new_remaining.insert(bit);
396				}
397			}
398	
399			if (switch_->full_case || pool.empty())
400				remaining.swap(new_remaining);
401		}
402	
403		return remaining;
404	}
