406	// extract trigger for side-effect cells like $print, $check
407	void ProcessTiming::extract_trigger(NetlistContext &netlist, Yosys::Cell *cell, RTLIL::SigBit enable)
408	{
409		auto &params = cell->parameters;
410	
411		cell->setPort(ID::EN, netlist.LogicAnd(background_enable, enable));
412	
413		switch (kind) {
414		case Implicit: {
415			params[ID::TRG_ENABLE] = false;
416			params[ID::TRG_WIDTH] = 0;
417			params[ID::TRG_POLARITY] = {};
418			cell->setPort(ID::TRG, {});
419			break;
420		}
421		case EdgeTriggered: {
422			params[ID::TRG_ENABLE] = true;
423			params[ID::TRG_WIDTH] = triggers.size();
424			std::vector<RTLIL::State> pol_bits;
425			RTLIL::SigSpec trg_signals;
426			for (auto trigger : triggers) {
427				pol_bits.push_back(trigger.edge_polarity ? RTLIL::S1 : RTLIL::S0);
428				trg_signals.append(trigger.signal);
429			}
430			params[ID::TRG_POLARITY] = RTLIL::Const(pol_bits);
431			cell->setPort(ID::TRG, trg_signals);
432			break;
433		}
434		case Initial: {
435			params[ID::TRG_ENABLE] = true;
436			params[ID::TRG_WIDTH] = 0;
437			params[ID::TRG_POLARITY] = {};
438			cell->setPort(ID::TRG, {});
439			break;
440		}
441		default:
442			log_abort();
443		}
444	}
