452	RTLIL::SigBit inside_comparison(EvalContext &eval, RTLIL::SigSpec left,
453									const ast::Expression &expr)
454	{
455		require(expr, !expr.type->isUnpackedArray());
456	
457		if (expr.kind == ast::ExpressionKind::ValueRange) {
458			const auto& vexpr = expr.as<ast::ValueRangeExpression>();
459			require(expr, vexpr.rangeKind == ast::ValueRangeKind::Simple);
460			ast_invariant(expr, vexpr.left().type->isMatching(*vexpr.right().type));
461			return eval.netlist.LogicAnd(
462				eval.netlist.Ge(left, eval(vexpr.left()), vexpr.left().type->isSigned()),
463				eval.netlist.Le(left, eval(vexpr.right()), vexpr.right().type->isSigned())
464			);
465		} else {
466			RTLIL::SigSpec expr_signal = eval(expr);
467			ast_invariant(expr, expr_signal.size() == left.size());
468	
469			if (expr.type->isIntegral()) {
470				require(expr, expr_signal.is_fully_const());
471				return eval.netlist.EqWildcard(left, expr_signal);
472			} else {
473				return eval.netlist.Eq(left, expr_signal);
474			}
475		}
476	}
