511	void VariableState::set(VariableBits lhs, RTLIL::SigSpec value)
512	{
513		log_assert(lhs.bitwidth() == (uint64_t)value.size());
514	
515		for (uint64_t i = 0; i < lhs.bitwidth(); i++) {
516			VariableBit bit = lhs[i];
517	
518			if (!revert.count(bit)) {
519				if (visible_assignments.count(bit))
520					revert[bit] = visible_assignments.at(bit);
521				else
522					revert[bit] = RTLIL::Sm;
523			}
524	
525			visible_assignments[bit] = value[i];
526		}
527	}
