529	RTLIL::SigSpec VariableState::evaluate(NetlistContext &netlist, VariableBits vbits)
530	{
531		RTLIL::SigSpec ret;
532		for (auto vbit : vbits) {
533			if (vbit.variable.kind == Variable::Dummy) {
534				ret.append(RTLIL::Sx);
535			} else if (visible_assignments.count(vbit)) {
536				ret.append(visible_assignments.at(vbit));
537			} else {
538				log_assert(vbit.variable.kind == Variable::Static);
539				ret.append(netlist.wire(*vbit.variable.get_symbol())[(int)vbit.offset]);
540			}
541		}
542		return ret;
543	}
