546	{
547		RTLIL::SigSpec ret;
548		for (uint64_t i = 0; i < vchunk.bitwidth(); i++) {
549			if (visible_assignments.count(vchunk[i])) {
550				ret.append(visible_assignments.at(vchunk[i]));
551			} else {
552				log_assert(vchunk.variable.kind == Variable::Static);
553				ret.append(netlist.wire(*vchunk.variable.get_symbol())[(int)(vchunk.base + i)]);
