564	std::pair<VariableBits, RTLIL::SigSpec> VariableState::restore(Map &save)
565	{
566		VariableBits lreverted;
567		RTLIL::SigSpec rreverted;
568	
569		for (auto pair : revert)
570			lreverted.append(pair.first);
571		lreverted.sort();
572	
573		//rreverted.reserve(lreverted.bitwidth());
574		for (auto bit : lreverted)
575			rreverted.append(visible_assignments.at(bit));
576	
577		for (auto pair : revert) {
578			if (pair.second == RTLIL::Sm)
579				visible_assignments.erase(pair.first);
580			else
581				visible_assignments[pair.first] = pair.second;
582		}
583	
584		save.swap(revert);
585		return {lreverted, rreverted};
586	}
