620	VariableBits EvalContext::lhs(const ast::Expression &expr, bool silent)
621	{
622		ast_invariant(expr, expr.kind != ast::ExpressionKind::Streaming);
623	
624		auto analyzed_lvalue = LValue::analyze(*this, expr, silent);
625		if (!analyzed_lvalue) {
626			// Return dummy, diagnostic has been issued in analyze
627			// if `silent` is not true
628			return Variable::dummy(expr.type->getBitstreamWidth());
629		}
630	
631		if (!analyzed_lvalue->is_static()) {
632			if (!silent) {
633				netlist.add_diag(diag::UnsupportedLhs, expr.sourceRange);
634			}
635			return Variable::dummy(expr.type->getBitstreamWidth());
636		}
637	
638		VariableBits ret = analyzed_lvalue->evaluate_vbits();
639		log_assert(ret.bitwidth() == expr.type->getBitstreamWidth());
640		return ret;
641	}
