654	void NetlistContext::add_continuous_driver(VariableBits lhs, RTLIL::SigSpec rhs)
655	{
656		VariableBits cl;
657		RTLIL::SigSpec cr;
658	
659		for (auto [base, size, chunk] : lhs.chunk_spans()) {
660			if (chunk.variable.is_special_net()) {
661				for (uint64_t i = 0; i < size; i++) {
662					special_net_drivers[chunk[i]].append(rhs[(int)(base + i)]);
663				}
664			} else {
665				cl.append(chunk);
666				cr.append(rhs.extract((int)base, (int)size));
667			}
668		}
669	
670		register_driven(cl);
671		connect(convert_static(cl), cr);
672	}
