674	RTLIL::SigSpec EvalContext::connection_lhs(ast::AssignmentExpression const &assign)
675	{
676		ast_invariant(assign, !assign.timingControl);
677		const ast::Expression *rexpr = &assign.right();
678	
679		if (ast::SimpleAssignmentPatternExpression::isKind(assign.left().kind)) {
680			auto &pattern_lexpr = assign.left().as<ast::SimpleAssignmentPatternExpression>();
681			RTLIL::SigSpec link;
682			auto els = pattern_lexpr.elements();
683			for (auto it = els.rbegin(); it != els.rend(); it++) {
684				ast_invariant(**it, (*it)->kind == ast::ExpressionKind::Assignment);
685				auto &inner_assign = (*it)->as<ast::AssignmentExpression>();
686				link.append(connection_lhs(inner_assign));
687			}
688			return link;
689		}
690	
691		VariableBits vbits = lhs(assign.left());
692		if (rexpr->kind == ast::ExpressionKind::EmptyArgument &&
693				!vbits.has_special_nets()) {
694			// early path
695			netlist.register_driven(vbits);
696			return netlist.convert_static(vbits);
697		}
698	
699		while (rexpr->kind == ast::ExpressionKind::Conversion)
700			rexpr = &rexpr->as<ast::ConversionExpression>().operand();
701		ast_invariant(assign, rexpr->kind == ast::ExpressionKind::EmptyArgument);
702		ast_invariant(assign, rexpr->type->isBitstreamType());
703	
704		RTLIL::SigSpec link = netlist.add_placeholder_signal(
705									rexpr->type->getBitstreamWidth());
706		netlist.add_continuous_driver(vbits,
707				apply_nested_conversion(assign.right(), link));
708		return link;
709	}
710	
711	VariableBits EvalContext::streaming_lhs(ast::StreamingConcatenationExpression const &expr)
712	{
713		require(expr, expr.isFixedSize());
714		VariableBits cat;
715	
716		for (auto stream : expr.streams()) {
717			require(*stream.operand, !stream.withExpr);
718			auto& op = *stream.operand;
719			VariableBits item;
720	
721			if (op.kind == ast::ExpressionKind::Streaming)
722				item = streaming_lhs(op.as<ast::StreamingConcatenationExpression>());
723			else
724				item = lhs(*stream.operand);
725	
726			cat = {cat, item};
727		}
728	
729		require(expr, expr.getSliceSize() <= std::numeric_limits<int>::max());
730		int slice = expr.getSliceSize();
731		if (slice == 0) {
732			return cat;
733		} else {
734			VariableBits reorder;
735			for (uint64_t i = 0; i < cat.bitwidth(); i += slice)
736				reorder = {reorder, cat.extract(i, std::min((uint64_t)slice, cat.bitwidth() - i))};
737			return reorder;
738		}
739	}
740	
741	RTLIL::SigSpec EvalContext::streaming(ast::StreamingConcatenationExpression const &expr)
742	{
743		require(expr, expr.isFixedSize());
744		RTLIL::SigSpec cat;
745		std::vector<RTLIL::SigSpec> parts;
746	
747		auto streams = expr.streams();
748		parts.reserve(streams.size());
749		for (auto stream : streams) {
750			require(*stream.operand, !stream.withExpr);
751			auto& op = *stream.operand;
752			RTLIL::SigSpec item;
753	
754			if (op.kind == ast::ExpressionKind::Streaming)
755				item = streaming(op.as<ast::StreamingConcatenationExpression>());
756			else
757				item = (*this)(*stream.operand);
758	
759			parts.push_back(item);
760		}
761	
762		// SigSpec appends LSB-first; streams were evaluated left-to-right above,
763		// so append them in reverse to preserve SystemVerilog ordering.
764		for (auto part_it = parts.rbegin(); part_it != parts.rend(); ++part_it)
765			cat.append(*part_it);
766	
767		require(expr, expr.getSliceSize() <= std::numeric_limits<int>::max());
768		int slice = expr.getSliceSize();
769		if (slice == 0) {
770			return cat;
771		} else {
772			RTLIL::SigSpec reorder;
773			std::vector<RTLIL::SigSpec> slices;
774			for (int i = 0; i < cat.size(); i += slice)
775				slices.push_back(cat.extract(i, std::min(slice, cat.size() - i)));
776			// Slice extraction also walks LSB-first, so rebuild in reverse order.
777			for (auto part_it = slices.rbegin(); part_it != slices.rend(); ++part_it)
778				reorder.append(*part_it);
779			return reorder;
780		}
781	}
782	
783	RTLIL::SigSpec EvalContext::apply_conversion(const ast::ConversionExpression &conv, RTLIL::SigSpec op)
784	{
785		const ast::Type &from = conv.operand().type->getCanonicalType();
786		const ast::Type &to = conv.type->getCanonicalType();
787	
788		log_assert(op.size() == (int) from.getBitstreamWidth());
789	
790		if (from.isIntegral() && to.isIntegral()) {
791			bool sign_extend = (conv.conversionKind == ast::ConversionKind::Propagated)
792									? to.isSigned() : from.isSigned();
793			op.extend_u0((int) to.getBitWidth(), sign_extend);
794			return op;
795		} else if (from.isBitstreamType() && to.isBitstreamType()) {
796			require(conv, from.getBitstreamWidth() == to.getBitstreamWidth());
797			return op;
798		} else {
799			unimplemented(conv);
800		}
801	}
802	
803	RTLIL::SigSpec EvalContext::apply_nested_conversion(const ast::Expression &expr, RTLIL::SigSpec op)
804	{
805		if (expr.kind == ast::ExpressionKind::EmptyArgument) {
806			return op;
807		} else if (expr.kind == ast::ExpressionKind::Conversion) {
808			auto &conv = expr.as<ast::ConversionExpression>();
809			RTLIL::SigSpec value = apply_nested_conversion(conv.operand(), op);
810			return apply_conversion(conv, value);
811		} else {
812			log_abort();
813		}
814	}
