816	RTLIL::SigSpec handle_past(EvalContext &eval, const ast::CallExpression &call)
817	{
818		NetlistContext &netlist = eval.netlist;
819		ProceduralContext *procedural = eval.procedural;
820	
821		// $past(expr) - returns the value of expr from the previous clock cycle
822		// $past(expr, num_cycles) - returns the value from num_cycles ago
823		// Note: Full signature is $past(expr, num_ticks, gating_expr, clocking_event) but we only support first 2 args
824		if (call.arguments().size() > 2) {
825			netlist.add_diag(diag::PastGatingClockingUnsupported, call.sourceRange);
826			return RTLIL::SigSpec(RTLIL::Sx, (int) call.type->getBitstreamWidth());
827		}
828		if (procedural == nullptr || procedural->timing.kind == ProcessTiming::Implicit
829				|| procedural->timing.triggers.size() != 1 || !procedural->timing_matches_process) {
830			netlist.add_diag(diag::SystemFunctionRequireClockedBlock, call.sourceRange) << call.getSubroutineName();
831			return RTLIL::SigSpec(RTLIL::Sx, (int) call.type->getBitstreamWidth());
832		}
833	
834		// Check num_cycles if specified (2nd argument)
835		int num_cycles = 1;
836		if (call.arguments().size() >= 2) {
837			auto cycles_result = call.arguments()[1]->eval(eval.const_);
838			ast_invariant(call, cycles_result.isInteger());
839			auto cycles_int = cycles_result.integer().as<int>();
840			num_cycles = cycles_int.value();
841		}
842	
843		auto arg = call.arguments()[0];
844		RTLIL::SigSpec current_val = eval(*arg);
845		int width = current_val.size();
846	
847		// Use the first trigger (clock) from the procedural timing
848		auto &trigger = procedural->timing.triggers[0];
849	
850		// Create a chain of DFFs for num_cycles delay
851		RTLIL::SigSpec prev_val = current_val;
852		RTLIL::SigSpec past_wire;
853	
854		for (int i = 0; i < num_cycles; i++) {
855			past_wire = netlist.add_placeholder_signal(width, "$past");
856			netlist.add_dffe(netlist.new_id("past"),
857				trigger.signal,
858				procedural->timing.background_enable,
859				prev_val,
860				past_wire,
861				trigger.edge_polarity,
862				true);
863			prev_val = past_wire;
864		}
865	
866		return past_wire;
867	}
