869	static const RTLIL::Const reverse_data(RTLIL::Const &orig, int width)
870	{
871		std::vector<RTLIL::State> bits;
872		log_assert(orig.size() % width == 0);
873		bits.reserve(orig.size());
874		for (int i = orig.size() - width; i >= 0; i -= width)
875			bits.insert(bits.end(), orig.begin() + i, orig.begin() + i + width);
876		return bits;
877	}
