884	int str_to_state_vect(std::vector<RTLIL::State> &data, const char *str, uint64_t mem_width, bool is_hex)
885	{
886		// All digits in string (MSB at index 0)
887		std::vector<uint8_t> digits;
888		std::vector<RTLIL::State> data_word;
889		data_word.reserve(mem_width);
890	
891		while (*str) {
892			if ('0' <= *str && *str <= '9')
893				digits.push_back(*str - '0');
894			else if ('a' <= *str && *str <= 'f')
895				digits.push_back(10 + *str - 'a');
896			else if ('A' <= *str && *str <= 'F')
897				digits.push_back(10 + *str - 'A');
898			else if(*str == 'x' || *str == 'X')
899				digits.push_back(0xf0);
900			else if (*str == 'z' || *str == 'Z')
901				digits.push_back(0xf1);
902			str++;
903		}
904	
905		// Either hex or binary for readmem[h/b]
906		int base = is_hex ? 16 : 2;
907		int bits_per_digit = is_hex ? 4 : 1;
908		
909		for (auto it = digits.rbegin(), e = digits.rend(); it != e; it++) {
910			if (*it > (base-1) && *it < 0xf0)
911				return 1;
912	
913			for (int i = 0; i < bits_per_digit; i++) {
914				int bitmask = 1 << i;
915				if (*it == 0xf0)
916					data_word.push_back(RTLIL::Sx);
917				else if (*it == 0xf1)
918					data_word.push_back(RTLIL::Sz);
919				else
920					data_word.push_back((*it & bitmask) ? RTLIL::S1 : RTLIL::S0);
921			}
922		}
923	
924		RTLIL::State msb = data_word.empty() ? RTLIL::S0 : data_word.back();
925	
926		// Truncate/expand word to memory width
927		if (msb == RTLIL::S0 || msb == RTLIL::S1)
928			data_word.resize(mem_width, RTLIL::S0);
929		else
930			data_word.resize(mem_width, msb);
931	
932		data.insert(data.end(), data_word.begin(), data_word.end());
933		return 0;
934	}
