936	// clang-format on
937	void handle_readmem(ProceduralContext &context, const ast::CallExpression &call)
938	{
939		NetlistContext &netlist = context.netlist;
940		std::string mem_filename;
941	
942		auto filename_arg = call.arguments()[0];
943		auto filename_result = filename_arg->eval(context.eval.const_);
944		if (filename_result.bad()) {
945			netlist.add_diag(diag::ErrorNonconstantArgument, filename_arg->sourceRange);
946			return;
947		}
948	
949		if (!filename_arg->isImplicitString()) {
950			auto &diag = netlist.add_diag(diag::ArgumentTypeUnsupported, filename_arg->sourceRange);
951			diag << filename_arg->type->toString();
952			return;
953		} else {
954			auto constval = filename_result.convertToStr();
955			mem_filename = constval.str();
956		}
957	
958		std::ifstream f;
959		f.open(mem_filename);
960	
961		// Try to find memory file relative to the source file containing readmem
962		if (f.fail()) {
963			slang::SourceLocation loc = call.sourceRange.start();
964			slang::BufferID buf_id = loc.buffer();
965			std::filesystem::path file_path = global_sourcemgr->getFullPath(buf_id);
966			std::string parent_path = file_path.parent_path().string();
967	
968			if (!parent_path.empty() &&
969					parent_path.back() != std::filesystem::path::preferred_separator)
970				parent_path += std::filesystem::path::preferred_separator;
971	
972			f.open(parent_path + mem_filename);
973		}
974	
975		if (f.fail() || mem_filename.size() == 0) {
976			auto &diag = netlist.add_diag(diag::ReadmemFileNotFound, filename_arg->sourceRange);
977			diag << mem_filename;
978			return;
979		}
980	
981		ast_invariant(call, ast::AssignmentExpression::isKind(call.arguments()[1]->kind));
982		auto &assign = call.arguments()[1]->as<ast::AssignmentExpression>();
983		auto &target_type = *assign.left().type;
984	
985		// Check the second argument matches an allowed target
986		if (!target_type.isUnpackedArray() ||
987				!ast::EmptyArgumentExpression::isKind(assign.right().kind)) {
988			netlist.add_diag(diag::UnsupportedLhs, assign.sourceRange);
989			return;
990		}
991	
992		VariableBits target = context.eval.lhs(assign.left());
993		slang::ConstantRange target_range = target_type.getFixedRange();
994		int32_t start_addr = target_range.lower();
995		int32_t finish_addr = target_range.upper();
996	
997		if (call.arguments().size() > 2) {
998			auto start_arg = call.arguments()[2];
999			auto start_result = start_arg->eval(context.eval.const_);
1000			// Check that start_addr argument is a constant value
1001			if (start_result.bad()) {
1002				netlist.add_diag(diag::ErrorNonconstantArgument, start_arg->sourceRange);
1003				return;
1004			}
1005			ast_invariant(call, start_result.isInteger());
1006			start_addr = start_result.integer().as<int32_t>().value();
1007			if (!target_range.containsPoint(start_addr)) {
1008				auto &diag =
1009						netlist.add_diag(diag::ReadmemAddressOutsideOfRange, start_arg->sourceRange);
1010				diag << start_addr;
1011				return;
1012			}
1013		}
1014	
1015		if (call.arguments().size() > 3) {
1016			auto finish_arg = call.arguments()[3];
1017			auto finish_result = finish_arg->eval(context.eval.const_);
1018			// Check that finish_addr argument is a constant value
1019			if (finish_result.bad()) {
1020				netlist.add_diag(diag::ErrorNonconstantArgument, finish_arg->sourceRange);
1021				return;
1022			}
1023			ast_invariant(call, finish_result.isInteger());
1024			finish_addr = finish_result.integer().as<int32_t>().value();
1025			if (!target_range.containsPoint(finish_addr)) {
1026				auto &diag =
1027						netlist.add_diag(diag::ReadmemAddressOutsideOfRange, finish_arg->sourceRange);
1028				diag << finish_addr;
1029				return;
1030			}
1031		}
1032	
1033		std::vector<RTLIL::State> data;
1034		uint64_t word_size = target_type.getArrayElementType()->getBitstreamWidth();
1035		bool in_comment = false;
1036		bool no_jumps = true;
1037		int num_words = 0;
1038		int increment = start_addr < finish_addr ? 1 : -1;
1039		int32_t cursor = start_addr;
1040		int32_t data_first_address = start_addr;
1041	
1042		slang::ConstantRange command_range(start_addr, finish_addr);
1043	
1044		auto flush_data = [&]() {
1045			RTLIL::Const const_(data);
1046			assert(const_.size() % word_size == 0);
1047	
1048			bool needs_reversal = (increment == -1 && target_range.isDescending()) ||
1049								  (increment == 1 && !target_range.isDescending());
1050	
1051			int nwords = const_.size() / word_size;
1052			// HDL address corresponding to the base of const_ after reversal
1053			int32_t hdl_base =
1054					needs_reversal ? data_first_address + (nwords - 1) * increment : data_first_address;
1055	
1056			uint32_t base = target_range.isDescending() ? hdl_base - target_range.right
1057														  : target_range.right - hdl_base;
1058	
1059			context.do_simple_assign(call.sourceRange.start(),
1060					target.extract(((uint64_t)base) * word_size, const_.size()),
1061					needs_reversal ? reverse_data(const_, word_size) : const_,
1062					/* blocking= */ true);
1063			data.clear();
1064		};
1065	
1066		while (!f.eof()) {
1067			std::string line, token;
1068			std::getline(f, line);
1069	
1070			// Remove multiline comments
1071			for (size_t i = 0; i < line.size(); i++) {
1072				if (in_comment && line.compare(i, 2, "*/") == 0) {
1073					line[i] = ' ';
1074					line[i + 1] = ' ';
1075					in_comment = false;
1076					continue;
1077				}
1078				if (!in_comment && line.compare(i, 2, "/*") == 0) {
1079					in_comment = true;
1080				}
1081				if (in_comment)
1082					line[i] = ' ';
1083			}
1084	
1085			std::istringstream iss(line);
1086			while (iss >> token) {
1087				if (token.compare(0, 2, "//") == 0)
1088					break;
1089	
1090				if (token[0] == '@') {
1091					token = token.substr(1);
1092					const char *nptr = token.c_str();
1093					char *endptr;
1094					int32_t next_addr = strtol(nptr, &endptr, 16);
1095					if (!*nptr || *endptr) {
1096						auto &diag = netlist.add_diag(diag::ReadmemInvalidAddress, call.sourceRange);
1097						diag << std::string(nptr) << mem_filename;
1098						return;
1099					}
1100	
1101					if (!command_range.containsPoint(next_addr)) {
1102						auto &diag =
1103								netlist.add_diag(diag::ReadmemAddressOutsideOfRange, call.sourceRange);
1104						diag << token;
1105						return;
1106					}
1107	
1108					// Flush data before jumping to the next address
1109					if (next_addr != cursor) {
1110						if (!data.empty())
1111							flush_data();
1112						cursor = next_addr;
1113						data_first_address = next_addr;
1114					}
1115					no_jumps = false;
1116					continue;
1117				}
1118	
1119				int res = str_to_state_vect(
1120						data, token.c_str(), word_size, call.getSubroutineName() == "$readmemh");
1121				if (res != 0) {
1122					// Can only occur when digit is greater than 1 for $readmemb
1123					auto &diag = netlist.add_diag(diag::ReadmemBadBinaryDigit, call.sourceRange);
1124					diag << mem_filename;
1125					return;
1126				}
1127				num_words++;
1128	
1129				if ((cursor == finish_addr) || (increment > 0 && cursor > finish_addr) ||
1130						(increment < 0 && cursor < finish_addr)) {
1131					break;
1132				}
1133	
1134				cursor += increment;
1135			}
1136		}
1137	
1138		if (!data.empty())
1139			flush_data();
1140	
1141		if (call.arguments().size() == 4 && no_jumps &&
1142				num_words != std::abs(finish_addr - start_addr) + 1) {
1143			auto &diag = netlist.add_diag(diag::ReadmemWordsRangeMismatch, call.sourceRange);
1144			diag << mem_filename;
1145		}
1146	}
