1149	void handle_display(ProceduralContext &context, const ast::CallExpression &call)
1150	{
1151		NetlistContext &netlist = context.netlist;
1152		auto cell = netlist.canvas->addCell(netlist.new_id(), ID($print));
1153		transfer_attrs(context.netlist, call, cell);
1154		context.set_effects_trigger(cell);
1155		cell->parameters[ID::PRIORITY] = --context.effects_priority;
1156		std::vector<Yosys::VerilogFmtArg> fmt_args;
1157		for (auto arg : call.arguments()) {
1158			log_assert(arg);
1159			Yosys::VerilogFmtArg fmt_arg = {};
1160			// TODO: location info in fmt_arg
1161			switch (arg->kind) {
1162			case ast::ExpressionKind::StringLiteral:
1163				fmt_arg.type = Yosys::VerilogFmtArg::STRING;
1164				fmt_arg.str = std::string{arg->as<ast::StringLiteral>().getValue()};
1165				fmt_arg.sig = {};
1166				break;
1167			case ast::ExpressionKind::Call:
1168				if (arg->as<ast::CallExpression>().getSubroutineName() == "$time") {
1169					fmt_arg.type = Yosys::VerilogFmtArg::TIME;
1170					break;
1171				} else if (arg->as<ast::CallExpression>().getSubroutineName() == "$realtime") {
1172					fmt_arg.type = Yosys::VerilogFmtArg::TIME;
1173					fmt_arg.realtime = true;
1174					break;
1175				} else {
1176					[[fallthrough]];
1177				}
1178			default:
1179				fmt_arg.type = Yosys::VerilogFmtArg::INTEGER;
1180				fmt_arg.sig = context.eval(*arg);
1181				fmt_arg.signed_ = arg->type->isSigned();
1182				break;
1183			}
1184			fmt_args.push_back(fmt_arg);
1185	
1186		}
1187		Yosys::Fmt fmt = {};
1188		// TODO: insert the actual module name
1189		fmt.parse_verilog(fmt_args, /* sformat_like */ false, /* default_base */ 10,
1190						  std::string{call.getSubroutineName()}, netlist.canvas->name);
1191		if (call.getSubroutineName() == "$display")
1192			fmt.append_literal("\n");
1193		fmt.emit_rtlil(cell);
1194	}
