1196	RTLIL::SigSpec EvalContext::sva(ast::Expression const &expr)
1197	{
1198		bool in_sva_expression_save = in_sva_expression;
1199		in_sva_expression = true;
1200		auto ret = (*this)(expr);
1201		in_sva_expression = in_sva_expression_save;
1202		return ret;
