1204	
1205	RTLIL::SigSpec EvalContext::operator()(ast::Expression const &expr)
1206	{
1207		RTLIL::SigSpec ret;
1208		size_t repl_count;
1209	
1210		AttributeGuard guard(netlist);
1211		transfer_attrs(netlist, expr, guard);
1212	
1213		// TODO: Interconnect (untyped) is unimplemented, waiting on slang width resolution
1214		if (expr.type->isUntypedType())
1215			unimplemented(expr);
1216	
1217		ast_invariant(expr, expr.kind != ast::ExpressionKind::Streaming);
1218		if (!(expr.type->isFixedSize() || expr.type->isVoid())) {
1219			auto &diag = netlist.add_diag(diag::FixedSizeRequired, expr.sourceRange);
1220			diag << expr.type->toString();
1221			goto error;
1222		}
1223	
1224		if (/* flag for testing */ !ignore_ast_constants ||
1225				expr.kind == ast::ExpressionKind::IntegerLiteral ||
1226				expr.kind == ast::ExpressionKind::RealLiteral ||
1227				expr.kind == ast::ExpressionKind::UnbasedUnsizedIntegerLiteral ||
1228				expr.kind == ast::ExpressionKind::NullLiteral ||
1229				expr.kind == ast::ExpressionKind::StringLiteral) {
1230			auto const_result = expr.eval(this->const_);
1231			if (const_result) {
1232				auto converted = netlist.convert_const(const_result, expr.sourceRange.start());
1233				if (converted) {
1234					ret = *converted;
1235					goto done;
1236				} else {
1237					goto error;
1238				}
1239			}
1240		}
1241	
1242		switch (expr.kind) {
1243		case ast::ExpressionKind::Assignment:
1244			{
1245				auto &assign = expr.as<ast::AssignmentExpression>();
1246				ast_invariant(expr, procedural != nullptr);
1247	
1248				if (assign.timingControl && !netlist.settings.ignore_timing.value_or(false))
1249					netlist.add_diag(diag::GenericTimingUnsyn, assign.timingControl->sourceRange);
1250	
1251				const ast::Expression *lvalue_save = lvalue;
1252				lvalue = &assign.left();
1253				procedural->assign_rvalue(assign, ret = (*this)(assign.right()));
1254	
1255				// TODO: this is a fixup for a specific scenario, we need to
1256				// check if there isn't some other general handling of return
1257				// values we should be doing
1258				if (assign.left().kind == ast::ExpressionKind::Streaming)
1259					ret = {};
1260	
1261				lvalue = lvalue_save;
1262				break;
1263			}
1264		case ast::ExpressionKind::Inside:
1265			{
1266				auto &inside_expr = expr.as<ast::InsideExpression>();
1267				RTLIL::SigSpec left = (*this)(inside_expr.left());
1268				RTLIL::SigSpec hits;
1269				require(inside_expr, inside_expr.left().type->isIntegral());
1270	
1271				for (auto elem : inside_expr.rangeList())
1272					hits.append(inside_comparison(*this, left, *elem));
1273	
1274				ret = netlist.ReduceBool(hits);
1275				ret.extend_u0(expr.type->getBitstreamWidth());
1276				break;
1277			}
1278		case ast::ExpressionKind::HierarchicalValue:
1279			{
1280				const ast::ValueSymbol &symbol = expr.as<ast::ValueExpressionBase>().symbol;
1281				if (!netlist.scopes_remap.count(symbol.getParentScope())
1282						&& !netlist.check_hier_ref(symbol, expr.sourceRange)) {
1283					goto error;
1284				}
1285			}
1286			[[fallthrough]];
1287		case ast::ExpressionKind::NamedValue:
1288			{
1289				const ast::Symbol &symbol = expr.as<ast::ValueExpressionBase>().symbol;
1290				if (netlist.is_inferred_memory(symbol)) {
1291					netlist.add_diag(diag::BadMemoryExpr, expr.sourceRange);
1292					goto error;
1293				}
1294	
1295				if (ast::ParameterSymbol::isKind(symbol.kind)) {
1296					auto &valsym = symbol.as<ast::ValueSymbol>();
1297					require(valsym, valsym.getInitializer());
1298					auto exprconst = valsym.getInitializer()->eval(this->const_);
1299					require(valsym, exprconst.isInteger());
1300					return convert_svint(exprconst.integer());
1301				}
1302	
1303				if (ast::ModportPortSymbol::isKind(symbol.kind) &&
1304						!netlist.scopes_remap.count(symbol.getParentScope())) {
1305					auto &modport_port = symbol.as<ast::ModportPortSymbol>();
1306					ast_invariant(symbol, modport_port.getConnectionExpr() != nullptr);
1307					return (*this)(*modport_port.getConnectionExpr());
1308				}
1309	
1310				ast_invariant(symbol, ast::ValueSymbol::isKind(symbol.kind));
1311				Variable variable1 = variable(symbol.as<ast::ValueSymbol>());
1312				log_assert((bool) variable1);
1313				if (procedural && (!in_sva_expression || variable1.kind != Variable::Static)) {
1314					if (procedural->timing.kind == ProcessTiming::Initial && ast::NetSymbol::isKind(symbol.kind)) {
1315						netlist.add_diag(diag::ReadingNetStateFromInitialBlockUnsupported, expr.sourceRange);
1316						ret = RTLIL::SigSpec(RTLIL::Sx, (int) expr.type->getBitstreamWidth());
1317						break;
1318					}
1319					ret = procedural->substitute_rvalue(variable1);
1320				} else {
1321					ret = netlist.convert_static(variable1);
1322				}
1323			}
1324			break;
1325		case ast::ExpressionKind::UnaryOp:
1326			{
1327				const ast::UnaryExpression &unop = expr.as<ast::UnaryExpression>();
1328				RTLIL::SigSpec left = (*this)(unop.operand());
1329	
1330				using UnOp = ast::UnaryOperator;
1331	
1332				if (unop.op == UnOp::Postincrement || unop.op == UnOp::Preincrement) {
1333					require(expr, procedural != nullptr);
1334					RTLIL::SigSpec add1 = netlist.Biop(
1335							ID($add), left, {RTLIL::S0, RTLIL::S1},
1336							unop.operand().type->isSigned(), unop.operand().type->isSigned(),
1337							left.size());
1338					procedural->do_simple_assign(expr.sourceRange.start(),
1339												 lhs(unop.operand()), add1, true);
1340					ret = (unop.op == UnOp::Preincrement) ? add1 : left;
1341					break;
1342				}
1343	
1344				if (unop.op == UnOp::Postdecrement || unop.op == UnOp::Predecrement) {
1345					require(expr, procedural != nullptr);
1346					RTLIL::SigSpec sub1 = netlist.Biop(
1347							ID($sub), left, {RTLIL::S0, RTLIL::S1},
1348							unop.operand().type->isSigned(), unop.operand().type->isSigned(),
1349							left.size());
1350					procedural->do_simple_assign(expr.sourceRange.start(),
1351												 lhs(unop.operand()), sub1, true);
1352					ret = (unop.op == UnOp::Predecrement) ? sub1 : left;
1353					break;
1354				}
1355	
1356				bool invert = false;
1357	
1358				RTLIL::IdString type;
1359				switch (unop.op) {
1360				case UnOp::Minus: type = ID($neg); break;
1361				case UnOp::Plus: type = ID($pos); break;
1362				case UnOp::LogicalNot: type = ID($logic_not); break;
1363				case UnOp::BitwiseNot: type = ID($not); break;
1364				case UnOp::BitwiseOr: type = ID($reduce_or); break;
1365				case UnOp::BitwiseAnd: type = ID($reduce_and); break;
1366				case UnOp::BitwiseNand: type = ID($reduce_and); invert = true; break;
1367				case UnOp::BitwiseNor: type = ID($reduce_or); invert = true; break;
1368				case UnOp::BitwiseXor: type = ID($reduce_xor); break;
1369				case UnOp::BitwiseXnor: type = ID($reduce_xnor); break;
1370				default:
1371					ast_unreachable(unop);
1372				}
1373	
1374				ret = netlist.Unop(
1375					type, left, unop.operand().type->isSigned(), expr.type->getBitstreamWidth()
1376				);
1377	
1378				if (invert)
1379					ret = netlist.LogicNot(ret);
1380			}
1381			break;
1382		case ast::ExpressionKind::BinaryOp:
1383			{
1384				const ast::BinaryExpression &biop = expr.as<ast::BinaryExpression>();
1385				RTLIL::SigSpec left = (*this)(biop.left());
1386				RTLIL::SigSpec right = (*this)(biop.right());
1387	
1388				bool invert;
1389				switch (biop.op) {
1390				case ast::BinaryOperator::WildcardEquality:
1391					invert = false;
1392					if (0) {
1393				case ast::BinaryOperator::WildcardInequality:
1394					invert = true;
1395					}
1396					if (!right.is_fully_const()) {
1397						netlist.add_diag(diag::NonconstWildcardEq, expr.sourceRange);
1398						ret = netlist.add_placeholder_signal(expr.type->getBitstreamWidth());
1399						return ret;
1400					}
1401					return netlist.Unop(
1402						invert ? ID($logic_not) : ID($reduce_bool),
1403						netlist.EqWildcard(left, right),
1404						false, expr.type->getBitstreamWidth()
1405					);
1406				default:
1407					break;
1408				}
1409	
1410				bool a_signed = biop.left().type->isSigned();
1411				bool b_signed = biop.right().type->isSigned();
1412	
1413				RTLIL::IdString type;
1414				switch (biop.op) {
1415				case ast::BinaryOperator::Add:      type = ID($add); break;
1416				case ast::BinaryOperator::Subtract: type = ID($sub); break;
1417				case ast::BinaryOperator::Multiply:	type = ID($mul); break;
1418				case ast::BinaryOperator::Divide:	type = ID($div); break;
1419				case ast::BinaryOperator::Mod:		type = ID($mod); break;
1420				case ast::BinaryOperator::BinaryAnd: type = ID($and); break;
1421				case ast::BinaryOperator::BinaryOr:	type = ID($or); break;
1422				case ast::BinaryOperator::BinaryXor:	type = ID($xor); break;
1423				case ast::BinaryOperator::BinaryXnor:	type = ID($xnor); break;
1424				case ast::BinaryOperator::Equality:		type = ID($eq); break;
1425				case ast::BinaryOperator::Inequality:	type = ID($ne); break;
1426				case ast::BinaryOperator::CaseInequality: type = ID($nex); break;
1427				case ast::BinaryOperator::CaseEquality: type = ID($eqx); break;
1428				case ast::BinaryOperator::GreaterThanEqual:	type = ID($ge); break;
1429				case ast::BinaryOperator::GreaterThan:		type = ID($gt); break;
1430				case ast::BinaryOperator::LessThanEqual:	type = ID($le); break;
1431				case ast::BinaryOperator::LessThan:			type = ID($lt); break;
1432				case ast::BinaryOperator::LogicalAnd:	type = ID($logic_and); break;
1433				case ast::BinaryOperator::LogicalOr:	type = ID($logic_or); break;
1434				case ast::BinaryOperator::LogicalImplication: type = ID($logic_or); left = netlist.LogicNot(left); a_signed = false; break;
1435				case ast::BinaryOperator::LogicalEquivalence: type = ID($eq); left = netlist.ReduceBool(left); right = netlist.ReduceBool(right); a_signed = b_signed = false; break;
1436				case ast::BinaryOperator::LogicalShiftLeft:	type = ID($shl); break;
1437				case ast::BinaryOperator::LogicalShiftRight:	type = ID($shr); break;
1438				case ast::BinaryOperator::ArithmeticShiftLeft:	type = ID($sshl); break;
1439				case ast::BinaryOperator::ArithmeticShiftRight:	type = ID($sshr); break;
1440				case ast::BinaryOperator::Power:	type = ID($pow); break;
1441				default:
1442					ast_unreachable(biop);
1443				}
1444	
1445				// fixups
1446				if (type.in(ID($shr), ID($shl)))
1447					a_signed = false;
1448				if (type.in(ID($shr), ID($shl), ID($sshr), ID($sshl)))
1449					b_signed = false;
1450	
1451				ret = netlist.Biop(
1452					type, left, right,
1453					a_signed, b_signed, expr.type->getBitstreamWidth()
1454				);
1455			}
1456			break;
1457		case ast::ExpressionKind::Conversion:
1458			{
1459				const ast::ConversionExpression &conv = expr.as<ast::ConversionExpression>();
1460				if (conv.isConstCast) {
1461					// See IEEE Std 1800-2017 section 16.14.6: the insides of a const cast
1462					// follow the rules of ordinary procedural evaluation
1463					bool in_sva_expression_save = in_sva_expression;
1464					in_sva_expression = false;
1465					ret = apply_conversion(conv, (*this)(conv.operand()));
1466					in_sva_expression = in_sva_expression_save;
1467				} else if (conv.operand().kind != ast::ExpressionKind::Streaming) {
1468					ret = apply_conversion(conv, (*this)(conv.operand()));
1469				} else {
1470					const ast::Type &to = conv.type->getCanonicalType();
1471					ast_invariant(conv, to.isBitstreamType());
1472	
1473					// evaluate the bitstream
1474					auto &stream_expr = conv.operand().as<ast::StreamingConcatenationExpression>();
1475					RTLIL::SigSpec stream = streaming(stream_expr);
1476	
1477					// pad to fit target size
1478					ast_invariant(conv, stream.size() <= (int) expr.type->getBitstreamWidth());
1479					ret = {stream, RTLIL::SigSpec(RTLIL::S0, expr.type->getBitstreamWidth() - stream.size())};
1480				}
1481			}
1482			break;
1483		case ast::ExpressionKind::IntegerLiteral:
1484			{
1485				const ast::IntegerLiteral &lit = expr.as<ast::IntegerLiteral>();
1486				ret = convert_svint(lit.getValue());
1487			}
1488			break;
1489		case ast::ExpressionKind::RangeSelect:
1490			{
1491				const ast::RangeSelectExpression &sel = expr.as<ast::RangeSelectExpression>();
1492				AddressingResolver addr(*this, sel);
1493				ret = addr.shift_down((*this)(sel.value()), sel.type->getBitstreamWidth());
1494			}
1495			break;
1496		case ast::ExpressionKind::ElementSelect:
1497			{
1498				const ast::ElementSelectExpression &elemsel = expr.as<ast::ElementSelectExpression>();
1499	
1500				if (netlist.is_inferred_memory(elemsel.value()) && !in_sva_expression) {
1501					int width = elemsel.type->getBitstreamWidth();
1502					std::string id = netlist.id(elemsel.value()
1503											.as<ast::ValueExpressionBase>().symbol);
1504					RTLIL::Cell *memrd = netlist.canvas->addCell(netlist.new_id(), ID($memrd_v2));
1505					memrd->setParam(ID::MEMID, id);
1506					memrd->setParam(ID::CLK_ENABLE, false);
1507					memrd->setParam(ID::CLK_POLARITY, false);
1508					memrd->setParam(ID::TRANSPARENCY_MASK, RTLIL::Const(0, 0));
1509					memrd->setParam(ID::COLLISION_X_MASK, RTLIL::Const(0, 0));
1510					memrd->setParam(ID::CE_OVER_SRST, false);
1511					memrd->setParam(ID::ARST_VALUE, RTLIL::Const(RTLIL::Sx, width));
1512					memrd->setParam(ID::SRST_VALUE, RTLIL::Const(RTLIL::Sx, width));
1513					memrd->setParam(ID::INIT_VALUE, RTLIL::Const(RTLIL::Sx, width));
1514					memrd->setPort(ID::CLK, RTLIL::Sx);
1515					memrd->setPort(ID::EN, RTLIL::S1);
1516					memrd->setPort(ID::ARST, RTLIL::S0);
1517					memrd->setPort(ID::SRST, RTLIL::S0);
1518					// TODO: signedness
1519					RTLIL::SigSpec addr = (*this)(elemsel.selector());
1520					memrd->setPort(ID::ADDR, addr);
1521					memrd->setParam(ID::ABITS, addr.size());
1522					ret = netlist.add_placeholder_signal(width);
1523					memrd->setPort(ID::DATA, ret);
1524					memrd->setParam(ID::WIDTH, width);
1525					transfer_attrs(netlist, expr, memrd);
1526					break;
1527				}
1528	
1529				AddressingResolver addr(*this, elemsel);
1530				ret = addr.mux((*this)(elemsel.value()), elemsel.type->getBitstreamWidth());
1531			}
1532			break;
1533		case ast::ExpressionKind::Concatenation:
1534			{
1535				const ast::ConcatenationExpression &concat = expr.as<ast::ConcatenationExpression>();
1536				auto operands = concat.operands();
1537				std::vector<RTLIL::SigSpec> parts;
1538				parts.reserve(operands.size());
1539				for (auto op : operands)
1540					parts.push_back((*this)(*op));
1541				// SigSpec appends LSB-first; operands are evaluated in source order
1542				// above and appended in reverse to preserve concatenation order.
1543				for (auto part_it = parts.rbegin(); part_it != parts.rend(); ++part_it)
1544					ret.append(*part_it);
1545			}
1546			break;
1547		case ast::ExpressionKind::SimpleAssignmentPattern:
1548		case ast::ExpressionKind::StructuredAssignmentPattern:
1549			{
1550				repl_count = 1;
1551	
1552				if (0) {
1553		case ast::ExpressionKind::ReplicatedAssignmentPattern:
1554					repl_count = *expr.as<ast::ReplicatedAssignmentPatternExpression>()
1555									.count().eval(const_).integer().as<size_t>();
1556				}
1557	
1558				auto &pattern_expr = static_cast<const ast::AssignmentPatternExpressionBase&>(expr);
1559				auto elements = pattern_expr.elements();
1560	
1561				ret = {};
1562				std::vector<RTLIL::SigSpec> parts;
1563				parts.reserve(elements.size());
1564				for (auto elem : elements)
1565					parts.push_back((*this)(*elem));
1566				// Assignment patterns use the same bit ordering as concatenations.
1567				for (auto part_it = parts.rbegin(); part_it != parts.rend(); ++part_it)
1568					ret.append(*part_it);
1569				ret = ret.repeat(repl_count);
1570			}
1571			break;
1572		case ast::ExpressionKind::ConditionalOp:
1573			{
1574				const auto &ternary = expr.as<ast::ConditionalExpression>();
1575	
1576				require(expr, ternary.conditions.size() == 1);
1577				require(expr, !ternary.conditions[0].pattern);
1578	
1579				ret = netlist.Mux(
1580					(*this)(ternary.right()),
1581					(*this)(ternary.left()),
1582					netlist.ReduceBool((*this)(*(ternary.conditions[0].expr)))
1583				);
1584			}
1585			break;
1586		case ast::ExpressionKind::Replication:
1587			{
1588				const auto &repl = expr.as<ast::ReplicationExpression>();
1589				auto count = repl.count().eval(const_);
1590				ast_invariant(expr, count.isInteger());
1591				int reps = count.integer().as<int>().value(); // TODO: checking int cast
1592				RTLIL::SigSpec concat = (*this)(repl.concat());
1593				for (int i = 0; i < reps; i++)
1594					ret.append(concat);
1595			}
1596			break;
1597		case ast::ExpressionKind::MemberAccess:
1598			{
1599				const auto &acc = expr.as<ast::MemberAccessExpression>();
1600				ret = extract_struct_field((*this)(acc.value()), acc);
1601			}
1602			break;
1603		case ast::ExpressionKind::Call:
1604			{
1605				const auto &call = expr.as<ast::CallExpression>();
1606				if (call.isSystemCall() && (call.getSubroutineName() == "$display"
1607						|| call.getSubroutineName() == "$write")) {
1608					require(expr, procedural != nullptr);
1609					handle_display(*procedural, call);
1610				} else if (call.isSystemCall()) {
1611					auto name = call.getSubroutineName();
1612					if (name == "$countones") {
1613						require(expr, call.arguments().size() == 1);
1614						auto arg = call.arguments()[0];
1615						auto sig = (*this)(*arg);
1616						ret = netlist.CountOnes(sig, (int)call.type->getBitstreamWidth());
1617					} else if (name == "$clog2") {
1618						ast_invariant(expr, call.arguments().size() == 1);
1619						auto arg = call.arguments()[0];
1620						auto sig = (*this)(*arg);
1621						ret = netlist.Clog2(sig, (int)call.type->getBitstreamWidth());
1622					} else if (name == "$past") {
1623						ret = handle_past(*this, call);
1624					} else if (name == "$signed" || name == "$unsigned") {
1625						require(expr, call.arguments().size() == 1);
1626						ret = (*this)(*call.arguments()[0]);
1627					} else if (name == "$readmemb" || name == "$readmemh") {
1628						require(expr, !(call.arguments().size() < 2 || call.arguments().size() > 4));
1629						handle_readmem(*procedural, call);
1630					} else {
1631						auto &d = netlist.add_diag(diag::UnsupportedSystemTask, expr.sourceRange);
1632						d << name;
1633						if (procedural && procedural->timing.kind == ProcessTiming::Initial)
1634							d.addNote(diag::NoteIgnoreInitial, expr.sourceRange.start());
1635						goto error;
1636					}
1637				} else {
1638					const auto &subr = *std::get<0>(call.subroutine);
1639					if (procedural) {
1640						ret = StatementExecutor(*procedural).handle_call(call);
1641					} else {
1642						require(subr, subr.subroutineKind == ast::SubroutineKind::Function);
1643						ProceduralContext context(netlist, ProcessTiming::implicit);
1644						StatementExecutor visitor(context);
1645						visitor.eval.ignore_ast_constants = ignore_ast_constants;
1646						ret = visitor.handle_call(call);
1647	
1648						RTLIL::Process *proc = netlist.canvas->addProcess(netlist.new_id());
1649						transfer_attrs(netlist, call, proc);
1650						context.copy_case_tree_into(proc->root_case);
1651					}
1652				}
1653			}
1654			break;
1655		case ast::ExpressionKind::LValueReference:
1656			ast_invariant(expr, lvalue != nullptr);
1657			ret = (*this)(*lvalue);
1658			break;
1659		default:
1660			netlist.add_diag(diag::LangFeatureUnsupported, expr.sourceRange);
1661			goto error;
1662		}
1663	
1664		if (0) {
1665	error:
1666		ret = RTLIL::SigSpec(RTLIL::Sx, (int) expr.type->getBitstreamWidth());
1667		}
1668	
1669	done:
1670		ast_invariant(expr, ret.size() == (int) expr.type->getBitstreamWidth());
1671		return ret;
1672	}
