1696	struct HierarchyQueue {
1697		template<class... Args>
1698		std::pair<NetlistContext&, bool> get_or_emplace(const ast::InstanceBodySymbol *symbol, Args&&... args)
1699		{
1700			if (netlists.count(symbol)) {
1701				return {*netlists.at(symbol), false};
1702			} else {
1703				NetlistContext *ref = new NetlistContext(args...);
1704				netlists[symbol] = ref;
1705				queue.push_back(ref);
1706				return {*ref, true};
1707			}
1708		}
1709	
1710		~HierarchyQueue()
1711		{
1712			for (auto netlist : queue)
1713				delete netlist;
1714		}
1715	
1716		std::map<const ast::InstanceBodySymbol *, NetlistContext *> netlists;
1717		std::vector<NetlistContext *> queue;
1718	};
