1766	struct PopulateNetlist : public TimingPatternInterpretor, public ast::ASTVisitor<PopulateNetlist, ast::VisitFlags::Statements> {
1767	public:
1768		HierarchyQueue &queue;
1769		NetlistContext &netlist;
1770		SynthesisSettings &settings;
1771		InferredMemoryDetector mem_detect;
1772		std::vector<NetlistContext> deferred_modules;
1773	
1774		PopulateNetlist(HierarchyQueue &queue, NetlistContext &netlist)
1775			: TimingPatternInterpretor(netlist.settings, (DiagnosticIssuer&) netlist, netlist.eval),
1776			  queue(queue), netlist(netlist), settings(netlist.settings),
1777			  mem_detect(settings, std::bind(&NetlistContext::should_dissolve, &netlist, std::placeholders::_1, nullptr), netlist.eval) {}
1778	
1779		void handle_comb_like_process(const ast::ProceduralBlockSymbol &symbol, const ast::Statement &body)
1780		{
1781			RTLIL::Process *proc = netlist.canvas->addProcess(netlist.new_id());
1782			transfer_attrs(netlist, body, proc);
1783	
1784			ProceduralContext procedure(netlist, ProcessTiming::implicit);
1785			body.visit(StatementExecutor(procedure));
1786	
1787			VariableBits all_driven = procedure.all_driven();
1788			Yosys::pool<VariableBit> dangling;
1789			if (symbol.procedureKind != ast::ProceduralBlockKind::AlwaysComb) {
1790				Yosys::pool<VariableBit> driven_pool = {all_driven.begin(), all_driven.end()};
1791				dangling =
1792					detect_possibly_unassigned_subset(driven_pool, procedure.root_case.get());
1793			}
1794	
1795			// left-hand side and right-hand side of the connections to be made
1796			RTLIL::SigSpec cr;
1797			VariableBits cl, latch_driven;
1798	
1799			for (auto driven_bit : all_driven) {
1800				if (!dangling.count(driven_bit)) {
1801					// No latch inferred
1802					cl.append(driven_bit);
1803					cr.append(procedure.vstate.visible_assignments.at(driven_bit));
1804				} else {
1805					latch_driven.append(driven_bit);
1806				}
1807			}
1808	
1809			if (symbol.procedureKind == ast::ProceduralBlockKind::AlwaysLatch && !cl.empty()) {
1810				for (auto chunk : cl.chunks()) {
1811					auto &diag = netlist.add_diag(diag::LatchNotInferred, symbol.location);
1812					diag << chunk.text();
1813				}
1814			}
1815	
1816			if (!latch_driven.empty()) {
1817				// map from a driven signal to the corresponding enable/staging signal
1818				// TODO: SigSig needlessly costly here
1819				Yosys::dict<VariableBit, RTLIL::SigSig> signaling;
1820				RTLIL::SigSpec enables, all_staging;
1821	
1822				latch_driven.sort_and_unify();
1823				for (auto chunk : latch_driven.chunks()) {
1824					RTLIL::SigSpec en = netlist.add_placeholder_signal(chunk.bitwidth());
1825					RTLIL::SigSpec staging = netlist.add_placeholder_signal(chunk.bitwidth());
1826	
1827					for (uint64_t i = 0; i < chunk.bitwidth(); i++) {
1828						RTLIL::Cell *cell = netlist.canvas->addDlatch(netlist.new_id(), en[i],
1829												staging[i], netlist.convert_static(chunk[i]), true);
1830						netlist.driven_variables.insert(chunk[i]);
1831						netlist.register_driven_variables.insert(chunk[i]);
1832						transfer_attrs(netlist, symbol, cell);
1833						signaling[chunk[i]] = {en[i], staging[i]};
1834					}
1835					enables.append(en);
1836					all_staging.append(staging);
1837				}
1838	
1839				procedure.root_case->aux_actions.push_back(
1840							{enables, RTLIL::SigSpec(RTLIL::S0, enables.size())});
1841				procedure.root_case->aux_actions.push_back(
1842							{all_staging, RTLIL::SigSpec(RTLIL::Sx, all_staging.size())});
1843				procedure.root_case->insert_latch_signaling(netlist, signaling);
1844			}
1845	
1846			procedure.copy_case_tree_into(proc->root_case);
1847			netlist.add_continuous_driver(cl, cr);
1848		}
1849	
1850		void handle_ff_process(const ast::ProceduralBlockSymbol &symbol,
1851							   const ast::SignalEventControl &clock,
1852							   const ast::StatementBlockSymbol *prologue_block,
1853							   std::vector<const ast::Statement *> prologue_statements,
1854							   const ast::Statement &sync_body,
1855							   std::span<AsyncBranch> async)
1856		{
1857			log_assert(symbol.getBody().kind == ast::StatementKind::Timed);
1858			const auto &timed = symbol.getBody().as<ast::TimedStatement>();
1859	
1860			RTLIL::Process *proc = netlist.canvas->addProcess(netlist.new_id());
1861			transfer_attrs(netlist, timed.stmt, proc);
1862	
1863			ProcessTiming prologue_timing(ProcessTiming::EdgeTriggered);
1864			{
1865				prologue_timing.triggers.push_back({netlist.eval(clock.expr), clock.edge == ast::EdgeKind::PosEdge, &clock});
1866				for (auto &abranch : async)	{
1867					RTLIL::SigSpec sig = netlist.convert_static(abranch.trigger);
1868					log_assert(sig.size() == 1);
1869					prologue_timing.triggers.push_back({sig, abranch.polarity, nullptr});
1870				}
1871			}
1872			ProceduralContext prologue(netlist, prologue_timing);
1873			EnterAutomaticScopeGuard prologue_guard(prologue.eval, prologue_block);
1874			{
1875				StatementExecutor visitor(prologue);
1876				for (auto stmt : prologue_statements)
1877					stmt->visit(visitor);
1878			}
1879			prologue.copy_case_tree_into(proc->root_case);
1880	
1881			struct Aload {
1882				RTLIL::SigBit trigger;
1883				bool trigger_polarity;
1884				VariableState values;
1885				const ast::Statement *ast_node;
1886			};
1887			std::vector<Aload> aloads;
1888			RTLIL::SigSpec prior_branch_taken;
1889	
1890			for (auto &async_branch : async) {
1891				RTLIL::SigSpec sig = netlist.convert_static(async_branch.trigger);
1892				log_assert(sig.size() == 1);
1893	
1894				ProcessTiming branch_timing(ProcessTiming::Implicit);
1895				RTLIL::SigSpec sig_depol = async_branch.polarity ? sig : netlist.LogicNot(sig);
1896				branch_timing.background_enable = netlist.LogicAnd(netlist.LogicNot(prior_branch_taken), sig_depol);
1897				prior_branch_taken.append(sig_depol);
1898	
1899				ProceduralContext branch(netlist, branch_timing);
1900				branch.timing_matches_process = false;
1901				EnterAutomaticScopeGuard branch_guard(branch.eval, prologue_block);
1902	
1903				branch.inherit_state(prologue);
1904				async_branch.body.visit(StatementExecutor(branch));
1905				branch.copy_case_tree_into(proc->root_case);
1906				aloads.push_back({
1907					sig, async_branch.polarity, branch.vstate, &async_branch.body
1908				});
1909				// TODO: check for non-constant load values and warn about sim/synth mismatch
1910			}
1911	
1912			if (aloads.size() > 1) {
1913				netlist.add_diag(diag::AloadOne, timed.timing.sourceRange);
1914				return;
1915			}
1916	
1917			{
1918				RTLIL::SigSpec event_guard = RTLIL::S1;
1919				if (clock.iffCondition)
1920					event_guard = netlist.ReduceBool(netlist.eval(*clock.iffCondition));
1921	
1922				ProcessTiming timing(ProcessTiming::EdgeTriggered);
1923				timing.background_enable = netlist.LogicAnd(netlist.LogicNot(prior_branch_taken), event_guard);
1924				timing.triggers.push_back({netlist.eval(clock.expr), clock.edge == ast::EdgeKind::PosEdge, &clock});
1925	
1926				ProceduralContext sync_branch(netlist, timing);
1927				if (!aloads.empty())
1928					sync_branch.timing_matches_process = false;
1929				EnterAutomaticScopeGuard guard(sync_branch.eval, prologue_block);
1930				sync_branch.inherit_state(prologue);
1931				sync_body.visit(StatementExecutor(sync_branch));
1932				sync_branch.copy_case_tree_into(proc->root_case);
1933	
1934				// FIXME: ignores variables not driven from the sync procedure
1935				VariableBits driven = sync_branch.all_driven();
1936				for (VariableChunk driven_chunk : driven.chunks()) {
1937					const ast::Type *type = &driven_chunk.variable.get_symbol()->getType();
1938					RTLIL::SigSpec assigned = sync_branch.vstate.evaluate(netlist, driven_chunk);
1939	
1940					AttributeGuard guard(netlist);
1941					transfer_attrs(netlist, symbol, guard);
1942	
1943					if (aloads.empty()) {
1944						for (auto [named_chunk, name] : generate_subfield_names(driven_chunk, type)) {
1945							log_assert(named_chunk.variable.get_symbol() != nullptr);
1946							auto symbol = named_chunk.variable.get_symbol();
1947							std::string base_name = "$driver$"s + netlist.unescaped_id(*symbol) + name;
1948	
1949							if (clock.edge == ast::EdgeKind::BothEdges) {
1950								if (clock.iffCondition)
1951									netlist.add_diag(diag::IffUnsupported, clock.iffCondition->sourceRange);
1952	
1953								netlist.add_dual_edge_aldff(base_name,
1954															timing.triggers[0].signal,
1955															RTLIL::S0,
1956															assigned.extract((int)(named_chunk.base - driven_chunk.base), (int)named_chunk.bitwidth()),
1957															netlist.convert_static(named_chunk),
1958															RTLIL::SigSpec(RTLIL::Sx, (int)named_chunk.bitwidth()),
1959															true);
1960							} else {
1961								netlist.add_dffe(base_name,
1962												timing.triggers[0].signal,
1963												event_guard,
1964												assigned.extract((int)(named_chunk.base - driven_chunk.base), (int)named_chunk.bitwidth()),
1965												netlist.convert_static(named_chunk),
1966												timing.triggers[0].edge_polarity,
1967												true);
1968							}
1969						}
1970					} else if (aloads.size() == 1) {
1971						VariableBits aldff_q;
1972						VariableBits dffe_q; // fallback
1973	
1974						for (uint64_t i = 0; i < driven_chunk.bitwidth(); i++) {
1975							// Is this variable bit assigned to from the async branch?
1976							// Depending on this we either use $aldff or $dffe to drive it
1977							if (aloads[0].values.visible_assignments.count(driven_chunk[i]))
1978								aldff_q.append(driven_chunk[i]);
1979							else
1980								dffe_q.append(driven_chunk[i]);
1981						}
1982	
1983						if (!aldff_q.empty()) {
1984							for (auto driven_chunk2 : aldff_q.chunks())
1985							for (auto [named_chunk, name] : generate_subfield_names(driven_chunk2, type)) {
1986								log_assert(named_chunk.variable.get_symbol() != nullptr);
1987								auto symbol = named_chunk.variable.get_symbol();
1988								std::string base_name = "$driver$"s + netlist.unescaped_id(*symbol) + name;
1989	
1990								if (clock.edge == ast::EdgeKind::BothEdges) {
1991									if (clock.iffCondition)
1992										netlist.add_diag(diag::IffUnsupported, clock.iffCondition->sourceRange);
1993	
1994									netlist.add_dual_edge_aldff(base_name,
1995																timing.triggers[0].signal,
1996																aloads[0].trigger,
1997																assigned.extract((int)(named_chunk.base - driven_chunk.base), (int)named_chunk.bitwidth()),
1998																netlist.convert_static(named_chunk),
1999																aloads[0].values.evaluate(netlist, named_chunk),
2000																aloads[0].trigger_polarity);
2001								} else {
2002									RTLIL::SigSpec next_value = assigned.extract((int)(named_chunk.base - driven_chunk.base), (int)named_chunk.bitwidth());
2003	
2004									netlist.add_aldffe(base_name,
2005													  timing.triggers[0].signal,
2006													  event_guard,
2007													  aloads[0].trigger,
2008													  next_value,
2009													  netlist.convert_static(named_chunk),
2010													  aloads[0].values.evaluate(netlist, named_chunk),
2011													  timing.triggers[0].edge_polarity,
2012													  /* en_polarity */ true,
2013													  aloads[0].trigger_polarity);
2014								}
2015							}
2016						}
2017	
2018						if (!dffe_q.empty()) {
2019							for (auto driven_chunk2 : dffe_q.chunks()) {
2020								auto &diag = netlist.add_diag(diag::MissingAload, aloads[0].ast_node->sourceRange);
2021								diag << netlist.id(*driven_chunk2.variable.get_symbol()) + driven_chunk2.slice_text();
2022								diag.addNote(diag::NoteDuplicateEdgeSense, timed.timing.sourceRange);
2023							}
2024	
2025							for (auto driven_chunk2 : dffe_q.chunks())
2026							for (auto [named_chunk, name] : generate_subfield_names(driven_chunk2, type)) {
2027								log_assert(named_chunk.variable.get_symbol() != nullptr);
2028								auto symbol = named_chunk.variable.get_symbol();
2029								std::string base_name = "$driver$"s + netlist.unescaped_id(*symbol) + name;
2030	
2031								bool has_event_guard = !(event_guard.is_fully_def() && event_guard.as_bool());
2032								netlist.add_dffe(base_name,
2033												 timing.triggers[0].signal,
2034												 has_event_guard ? timing.background_enable : aloads[0].trigger,
2035												 assigned.extract((int)(named_chunk.base - driven_chunk.base), (int)named_chunk.bitwidth()),
2036												 netlist.convert_static(named_chunk),
2037												 timing.triggers[0].edge_polarity,
2038												 has_event_guard ? true : !aloads[0].trigger_polarity);
2039							}
2040						}
2041					} else {
2042						log_abort();
2043					}
2044				}
2045	
2046				for (auto vbit : driven) {
2047					netlist.driven_variables.insert(vbit);
2048					netlist.register_driven_variables.insert(vbit);
2049				}
2050			}
2051		}
2052	
2053		void handle_initial_process(const ast::ProceduralBlockSymbol &, const ast::Statement &body) {
2054			if (settings.ignore_initial.value_or(false))
2055				return;
2056	
2057			ProceduralContext procedure(netlist, ProcessTiming::initial);
2058			body.visit(StatementExecutor(procedure));
2059		}
2060	
2061		void handle(const ast::ProceduralBlockSymbol &symbol)
2062		{
2063			if (symbol.isFromAssertion &&
2064					symbol.procedureKind == ast::ProceduralBlockKind::Always) {
2065				const ast::StatementBlockSymbol *block_symbol = nullptr;
2066				const ast::Statement *body = &symbol.getBody();
2067				if (ast::BlockStatement::isKind(body->kind)) {
2068					auto &block = body->as<ast::BlockStatement>();
2069					block_symbol = block.blockSymbol;
2070					body = &block.body;
2071				}
2072				ast_invariant(symbol, ast::ConcurrentAssertionStatement::isKind(body->kind) ||
2073										ast::ImmediateAssertionStatement::isKind(body->kind));
2074				if (!netlist.settings.ignore_assertions.value_or(false)) {
2075					if (ast::ConcurrentAssertionStatement::isKind(body->kind)) {
2076						process_freestanding_sva_property(netlist, body->as<ast::ConcurrentAssertionStatement>(),
2077														  block_symbol);
2078					} else {
2079						ProceduralContext procedure(netlist, ProcessTiming::implicit);
2080						symbol.getBody().visit(StatementExecutor(procedure));
2081						RTLIL::Process *rtlil_proc = netlist.canvas->addProcess(netlist.new_id());
2082						transfer_attrs(netlist, symbol, rtlil_proc);
2083						procedure.copy_case_tree_into(rtlil_proc->root_case);
2084					}
2085				}
2086			} else {
2087				interpret(symbol);
2088			}
2089		}
2090	
2091		void handle(const ast::NetSymbol &symbol)
2092		{
2093			if (symbol.getInitializer())
2094				netlist.add_continuous_driver(Variable::from_symbol(&symbol),
2095					netlist.eval(*symbol.getInitializer()));
2096		}
2097	
2098		void handle(const ast::PortSymbol &symbol)
2099		{
2100			if (symbol.getParentScope()->getContainingInstance() != &netlist.realm)
2101				return;
2102	
2103			if (!symbol.internalSymbol || symbol.internalSymbol->name.compare(symbol.name)) {
2104				netlist.add_diag(diag::PortCorrespondence, symbol.location);
2105				return;
2106			}
2107	
2108			RTLIL::Wire *w = netlist.wire(*symbol.internalSymbol).as_wire();
2109			log_assert(w);
2110			switch (symbol.direction) {
2111			case ast::ArgumentDirection::In:
2112				if (is_special_net(*symbol.internalSymbol)) {
2113					auto &diag = netlist.add_diag(diag::InputPortCannotBeSpecialNet, symbol.location);
2114					auto &net = symbol.internalSymbol->as<ast::NetSymbol>();
2115					diag << net.netType.name;
2116					return;
2117				}
2118				netlist.register_driven(*symbol.internalSymbol);
2119				w->port_input = true;
2120				break;
2121			case ast::ArgumentDirection::InOut:
2122				if (is_special_net(*symbol.internalSymbol)) {
2123					auto &diag = netlist.add_diag(diag::InputPortCannotBeSpecialNet, symbol.location);
2124					auto &net = symbol.internalSymbol->as<ast::NetSymbol>();
2125					diag << net.netType.name;
2126					return;
2127				}
2128				netlist.register_driven(*symbol.internalSymbol);
2129				w->port_input = true;
2130				w->port_output = true;
2131				break;
2132			case ast::ArgumentDirection::Out:
2133				w->port_output = true;
2134				break;
2135			case ast::ArgumentDirection::Ref:
2136				netlist.add_diag(diag::RefUnsupported, symbol.location);
2137				break;
2138			}
2139		}
2140	
2141		void handle(const ast::MultiPortSymbol &sym)
2142		{
2143			if (sym.getParentScope()->getContainingInstance() != &netlist.realm)
2144				return;
2145	
2146			netlist.add_diag(diag::MultiportUnsupported, sym.location);
2147		}
2148	
2149		void inline_port_connection(const ast::PortSymbol &port, RTLIL::SigSpec connection, [[maybe_unused]] slang::SourceRange range)
2150		{
2151			if (port.isNullPort)
2152				return;
2153	
2154			VariableBits internal_signal;
2155			if (auto expr = port.getInternalExpr()) {
2156				internal_signal = netlist.eval.lhs(*expr);
2157			} else {
2158				ast_invariant(port, ast::ValueSymbol::isKind(port.internalSymbol->kind));
2159				internal_signal = Variable::from_symbol(&port.internalSymbol->as<ast::ValueSymbol>());
2160			}
2161			ast_invariant(port, internal_signal.bitwidth() == (uint64_t)connection.size());
2162			ast_invariant(port, port.direction == ast::ArgumentDirection::In);
2163			netlist.add_continuous_driver(internal_signal, connection);
2164		}
2165	
2166		void inline_port_connection(const ast::PortSymbol &port, VariableBits connection, [[maybe_unused]] slang::SourceRange range)
2167		{
2168			if (port.isNullPort)
2169				return;
2170	
2171			VariableBits internal_signal;
2172			if (auto expr = port.getInternalExpr()) {
2173				internal_signal = netlist.eval.lhs(*expr);
2174			} else {
2175				ast_invariant(port, ast::ValueSymbol::isKind(port.internalSymbol->kind));
2176				internal_signal = Variable::from_symbol(&port.internalSymbol->as<ast::ValueSymbol>());
2177			}
2178			log_assert(internal_signal.bitwidth() == connection.bitwidth());
2179	
2180			switch (port.direction) {
2181			case ast::ArgumentDirection::Out:
2182				netlist.add_continuous_driver(connection, netlist.convert_static(internal_signal));
2183				break;
2184			case ast::ArgumentDirection::In:
2185				netlist.add_continuous_driver(internal_signal, netlist.convert_static(connection));
2186				break;
2187			case ast::ArgumentDirection::InOut:
2188			case ast::ArgumentDirection::Ref:
2189				ast_unreachable(port);
2190			}
2191		}
2192	
2193		void inline_port_connection_driver(const ast::PortSymbol &port, RTLIL::SigSpec connection, [[maybe_unused]] slang::SourceRange range)
2194		{
2195			if (port.isNullPort)
2196				return;
2197	
2198			VariableBits internal_signal;
2199			if (auto expr = port.getInternalExpr()) {
2200				internal_signal = netlist.eval.lhs(*expr);
2201			} else {
2202				ast_invariant(port, ast::ValueSymbol::isKind(port.internalSymbol->kind));
2203				internal_signal = Variable::from_symbol(&port.internalSymbol->as<ast::ValueSymbol>());
2204			}
2205			ast_invariant(port, internal_signal.bitwidth() == (uint64_t)connection.size());
2206			ast_invariant(port, port.direction == ast::ArgumentDirection::Out);
2207			netlist.connect(connection, netlist.convert_static(internal_signal));
2208		}
2209	
2210		void handle(const ast::InstanceSymbol &sym)
2211		{
2212			if (sym.getDefinition().definitionKind == ast::DefinitionKind::Program) {
2213				netlist.add_diag(diag::ProgramUnsupported, sym.location);
2214				return;
2215			}
2216	
2217			// blackboxes get special handling no matter the hierarchy mode
2218			if (sym.isModule() && netlist.is_blackbox(sym.body.getDefinition())) {
2219				RTLIL::Cell *cell = netlist.canvas->addCell(netlist.id(sym), RTLIL::escape_id(std::string(sym.body.name)));
2220				cell->set_string_attribute(ID::hdlname, netlist.hdlname(sym));
2221	
2222				for (auto *conn : sym.getPortConnections()) {
2223					slang::SourceLocation loc;
2224					if (auto expr = conn->getExpression())
2225						loc = expr->sourceRange.start();
2226					else
2227						loc = sym.location;
2228	
2229					switch (conn->port.kind) {
2230					case ast::SymbolKind::MultiPort:
2231					case ast::SymbolKind::InterfacePort: {
2232						auto &diag = netlist.add_diag(diag::UnsupportedBlackboxConnection, loc);
2233						diag << (conn->port.kind == ast::SymbolKind::MultiPort ? "multi"s : "interface"s);
2234						break;
2235					}
2236					case ast::SymbolKind::Port: {
2237						auto &port = conn->port.as<ast::PortSymbol>();
2238						if (!conn->getExpression())
2239							continue;
2240						auto &expr = *conn->getExpression();
2241						switch (port.direction) {
2242						case ast::ArgumentDirection::InOut:
2243						case ast::ArgumentDirection::Out: {
2244							ast_invariant(expr, ast::AssignmentExpression::isKind(expr.kind));
2245							auto &assign = expr.as<ast::AssignmentExpression>();
2246							cell->setPort(id(conn->port.name), netlist.eval.connection_lhs(assign));
2247							break;
2248						}
2249						case ast::ArgumentDirection::In: {
2250							cell->setPort(id(conn->port.name), netlist.eval(expr));
2251							break;
2252						}
2253						case ast::ArgumentDirection::Ref: {
2254							auto &diag = netlist.add_diag(diag::RefUnsupported, loc);
2255							diag << port.name;
2256						}
2257						}
2258						break;
2259					}
2260					default:
2261						ast_unreachable(sym);
2262					}
2263				}
2264	
2265				sym.body.visit(ast::makeVisitor([&](auto&, const ast::ParameterSymbol &symbol) {
2266					auto converted = netlist.convert_const(symbol.getValue(), symbol.location);
2267					if (converted) {
2268						if (symbol.isImplicitString(slang::SourceRange(sym.location, sym.location))
2269								&& converted->size() % 8 == 0) {
2270							converted->flags |= RTLIL::CONST_FLAG_STRING;
2271						}
2272						cell->setParam(RTLIL::escape_id(std::string(symbol.name)), *converted);
2273					}
2274				}, [&](auto&, const ast::TypeParameterSymbol &symbol) {
2275					netlist.add_diag(diag::BboxTypeParameter, symbol.location);
2276				}, [&](auto&, const ast::InstanceSymbol&) {
2277					// no-op
2278				}));
2279				transfer_attrs(netlist, sym, cell);
2280				export_blackbox_to_rtlil(netlist, sym, netlist.canvas->design);
2281				return;
2282			}
2283	
2284			if (netlist.should_dissolve(sym)) {
2285				sym.body.visit(*this);
2286	
2287				for (auto *conn : sym.getPortConnections()) {
2288					// Empty connections ".foo()" are without effect
2289					if (!conn->getExpression())
2290						continue;
2291					auto &expr = *conn->getExpression();
2292	
2293					switch (conn->port.kind) {
2294					case ast::SymbolKind::InterfacePort:
2295					case ast::SymbolKind::ModportPort:
2296						// Interface port connections are handled by transparent named value
2297						// lookup through the port
2298						continue;
2299	
2300					case ast::SymbolKind::MultiPort: {
2301						auto &multiport = conn->port.as<ast::MultiPortSymbol>();
2302						switch (multiport.direction) {
2303						case ast::ArgumentDirection::In: {
2304							RTLIL::SigSpec connection = netlist.eval(expr);
2305							int offset = 0;
2306							for (auto component : multiport.ports) {
2307								int width = component->getType().getBitstreamWidth();
2308								inline_port_connection(*component, connection.extract(offset, width), expr.sourceRange);
2309								offset += width;
2310							}
2311							ast_invariant(expr, offset == (int) multiport.getType().getBitstreamWidth());
2312							break;
2313						}
2314						case ast::ArgumentDirection::Out: {
2315							ast_invariant(expr, expr.kind == ast::ExpressionKind::Assignment);
2316							auto &assign = expr.as<ast::AssignmentExpression>();
2317	
2318							if (assign.right().kind != ast::ExpressionKind::EmptyArgument) {
2319								// If for all components in multiport.ports the component direction
2320								// was out, we could handle this case via connection_lhs with a bit of
2321								// extra effort. For now we issue a blanket error.
2322								auto &diag = netlist.add_diag(diag::MultiPortConversion, expr.sourceRange);
2323								diag << multiport.name;
2324								break;
2325							}
2326	
2327							VariableBits connection = netlist.eval.lhs(assign.left());
2328							ast_invariant(expr, connection.bitwidth() == multiport.getType().getBitstreamWidth());
2329							int offset = 0;
2330							for (auto component : multiport.ports) {
2331								int width = component->getType().getBitstreamWidth();
2332								inline_port_connection(*component, connection.extract(offset, width), expr.sourceRange);
2333								offset += width;
2334							}
2335							ast_invariant(expr, offset == (int) multiport.getType().getBitstreamWidth());
2336							break;
2337						}
2338						case ast::ArgumentDirection::InOut: {
2339							auto &diag = netlist.add_diag(diag::InlinedInOutUnsupported, expr.sourceRange);
2340							diag << multiport.name;
2341							break;
2342						}
2343						case ast::ArgumentDirection::Ref: {
2344							auto &diag = netlist.add_diag(diag::RefUnsupported, expr.sourceRange);
2345							diag << multiport.name;
2346							break;
2347						}
2348						}
2349						break;
2350					}
2351					case ast::SymbolKind::Port: {
2352						auto &port = conn->port.as<ast::PortSymbol>();
2353						switch (port.direction) {
2354						case ast::ArgumentDirection::In:
2355							inline_port_connection(port, netlist.eval(expr), expr.sourceRange);
2356							break;
2357						case ast::ArgumentDirection::Out: {
2358							ast_invariant(expr, ast::AssignmentExpression::isKind(expr.kind));
2359							auto &assign = expr.as<ast::AssignmentExpression>();
2360							inline_port_connection_driver(port, netlist.eval.connection_lhs(assign), expr.sourceRange);	
2361							break;
2362						}
2363						case ast::ArgumentDirection::InOut: {
2364							auto &diag = netlist.add_diag(diag::InlinedInOutUnsupported, expr.sourceRange);
2365							diag << port.name;
2366							break;
2367						}
2368						case ast::ArgumentDirection::Ref: {
2369							auto &diag = netlist.add_diag(diag::RefUnsupported, expr.sourceRange);
2370							diag << port.name;
2371							break;
2372						}
2373						}
2374						break;
2375					}
2376					default:
2377						ast_unreachable(conn->port);
2378					}

