3554		std::string wrap_text(std::string desc, size_t width = 70)
3555		{
3556		    constexpr const char* indent = "        ";
3557	
3558		    std::replace(desc.begin(), desc.end(), '\n', ' ');
3559		    std::replace(desc.begin(), desc.end(), '\r', ' ');
3560	
3561		    std::string result;
3562		    size_t pos = 0;
3563	
3564		    while (pos < desc.size()) {
3565		        while (pos < desc.size() && desc[pos] == ' ')
3566		            ++pos;
3567	
3568		        if (pos >= desc.size())
3569		            break;
3570	
3571		        if (desc.size() - pos <= width) {
3572		            result += desc.substr(pos);
3573		            break;
3574		        }
3575	
3576		        size_t end = desc.rfind(' ', pos + width);
3577		        if (end == std::string::npos || end < pos)
3578		            end = pos + width;
3579	
3580		        result += desc.substr(pos, end - pos);
3581		        result += '\n';
3582		        result += indent;
3583	
3584		        pos = end;
3585		    }
3586		    return result;
3587		}
