3610		std::optional<std::string> read_heredoc(std::vector<std::string> &args)
3611		{
3612			std::string eot;
3613	
3614			if (!args.empty() && args.back().compare(0, 2, "<<") == 0) {
3615				eot = args.back().substr(2);
3616				args.pop_back();
3617			} else if (args.size() >= 2 && args[args.size() - 2] == "<<") {
3618				eot = args.back();
3619				args.pop_back();
3620				args.pop_back();
3621			} else {
3622				return {};
3623			}
3624	
3625			if (eot.empty())
3626				log_error("Missing EOT marker for reading a here-document\n");
3627	
3628			std::string buffer;
3629			bool in_script = current_script_file != nullptr;
3630	
3631			while (true) {
3632				char line[4096];
3633				if (!fgets(line, sizeof(line), in_script ? current_script_file : stdin))
3634					log_error("Unexpected EOF reading a here-document\n");
3635	
3636				const char *p = line;
3637				while (*p == ' ' || *p == '\t' || *p == '\r' || *p == '\n')
3638					p++;
3639	
3640				if (!strncmp(p, eot.data(), eot.size()) &&
3641					(*(p + eot.size()) == '\r' || *(p + eot.size()) == '\n'))
3642					break;
3643				else
3644					buffer += line;
3645			}
3646	
3647			return buffer;
3648		}
