3650		// There are three cases handled by this function:
3651		// 1. Normal mode; no expected diagnostics. Return `false` to continue executing.
3652		// 2. Test mode; expected diagnostic found. Return `true` to exit early with success.
3653		// 3a. Test mode; expected diagnostic not found but more could appear later. Return `false`.
3654		// 3b. Test mode; expected diagnostic not found. Use `log_error()` to exit early with failure.
3655		bool check_diagnostics(slang::DiagnosticEngine &diagEngine, const slang::SmallVector<slang::Diagnostic> &diags, bool last)
3656		{
3657			if (expected_diagnostic.empty())
3658				return false;
3659	
3660			for (auto &diag : diags) {
3661				auto message = diagEngine.formatMessage(diag);
3662				if (message == expected_diagnostic) {
3663					log("Expected diagnostic `%s' found\n", expected_diagnostic.c_str());
3664					expected_diagnostic.clear();
3665					return true;
3666				}
3667			}
3668			if (last)
3669				log_error("Expected diagnostic `%s' but none emitted\n", expected_diagnostic.c_str());
3670			else
3671				return false;
3672		}
