3674		void execute(std::istream *&f, std::string filename, std::vector<std::string> args, RTLIL::Design *design) override
3675		{
3676			(void) f;
3677			(void) filename;
3678			log_header(design, "Executing SLANG frontend.\n");
3679	
3680			auto guard = slang::OS::captureOutput([&](std::string_view text, bool) { log("%s", std::string(text).c_str()); });
3681			// names of RTLIL modules added in this invocation; does not include blackboxes
3682			std::vector<RTLIL::IdString> emitted_module_names;
3683			slang::driver::Driver driver;
3684			driver.addStandardArgs();
3685			SynthesisSettings settings;
3686			settings.addOptions(driver.cmdLine);
3687			diag::setup_messages(driver.diagEngine);
3688	
3689			{
3690				if (auto heredoc = read_heredoc(args)) {
3691					auto buffer = driver.sourceManager.assignText("<inlined>", std::string_view{heredoc.value()});
3692					driver.sourceLoader.addBuffer(buffer);
3693				}
3694	
3695				args.insert(args.begin() + 1, default_options.begin(), default_options.end());
3696	
3697				std::vector<std::unique_ptr<char[]>> c_args_guard;
3698				std::vector<char *> c_args;
3699	
3700				for (auto arg : args) {
3701					char *c = new char[arg.size() + 1];
3702					strcpy(c, arg.c_str());
3703					c_args_guard.emplace_back(c);
3704					c_args.push_back(c);
3705				}
3706	
3707				if (!driver.parseCommandLine(c_args.size(), &c_args[0]))
3708					log_cmd_error("Bad command\n");
3709			}
3710	
3711			fixup_options(settings, driver);
3712			if (!driver.processOptions())
3713				log_cmd_error("Bad command\n");
3714			catch_forbidden_options(driver);
3715	
3716			try {
3717				if (!driver.parseAllSources())
3718					log_error("Parsing failed; see full log for details\n");
3719	
3720				auto compilation = driver.createCompilation();
3721	
3722				if (settings.extern_modules.value_or(true))
3723					import_blackboxes_from_rtlil(driver.sourceManager, *compilation, design);
3724	
3725				if (settings.dump_ast.value_or(false)) {
3726					slang::JsonWriter writer;
3727					writer.setPrettyPrint(true);
3728					ast::ASTSerializer serializer(*compilation, writer);
3729					serializer.serialize(compilation->getRoot());
3730					std::cout << writer.view() << std::endl;
3731				}
3732	
3733				bool in_succesful_failtest = false;
3734	
3735				driver.reportCompilation(*compilation,/* quiet */ false);
3736				if (check_diagnostics(driver.diagEngine, compilation->getAllDiagnostics(), /*last=*/false))
3737					in_succesful_failtest = true;
3738	
3739				if (driver.diagEngine.getNumErrors()) {
3740					// Stop here should there have been any errors from AST compilation,
3741					// PopulateNetlist requires a well-formed AST without error nodes
3742					(void) driver.reportDiagnostics(/* quiet */ false);
3743					if (!in_succesful_failtest)
3744						log_error("Design elaboration failed; see full log for details\n");
3745					return;
3746				}
3747	
3748				if (settings.ast_compilation_only.value_or(false)) {
3749					(void) driver.reportDiagnostics(/* quiet */ false);
3750					return;
3751				}
3752	
3753				global_compilation = &(*compilation);
3754				global_sourcemgr = compilation->getSourceManager();
3755	
3756				HierarchyQueue hqueue;
3757				for (auto instance : compilation->getRoot().topInstances) {
3758					if (instance->getDefinition().definitionKind == ast::DefinitionKind::Program) {
3759						slang::Diagnostic program_diag(diag::ProgramUnsupported, instance->location);
3760						driver.diagEngine.issue(program_diag);
3761						continue;
3762					}
3763	
3764					auto ref_body = &get_instance_body(settings, *instance);
3765					log_assert(ref_body->parentInstance);
3766					auto [netlist, new_] = hqueue.get_or_emplace(ref_body, design, settings,
3767																 *compilation, *ref_body->parentInstance);
3768					log_assert(new_);
3769					netlist.canvas->attributes[ID::top] = 1;
3770				}
3771	
3772				for (int i = 0; i < (int) hqueue.queue.size(); i++) {
3773					NetlistContext &netlist = *hqueue.queue[i];
3774					emitted_module_names.push_back(netlist.canvas->name);
3775	
3776					if (netlist.disabled)
3777						continue;
3778	
3779					PopulateNetlist populate(hqueue, netlist);
3780					netlist.realm.visit(populate);
3781	
3782					slang::Diagnostics diags;
3783					diags.append_range(populate.mem_detect.issued_diagnostics);
3784					diags.append_range(netlist.issued_diagnostics);
3785					diags.sort(driver.sourceManager);
3786	
3787					if (check_diagnostics(driver.diagEngine, diags, /*last=*/false))
3788						in_succesful_failtest = true;
3789	
3790					for (int i = 0; i < (int) diags.size(); i++) {
3791						if (i > 0 && diags[i] == diags[i - 1])
3792							continue;
3793						driver.diagEngine.issue(diags[i]);
3794					}
3795				}
3796	
3797				if (check_diagnostics(driver.diagEngine, {}, /*last=*/true))
3798					in_succesful_failtest = true;
3799	
3800				if (!driver.reportDiagnostics(/* quiet */ false)) {
3801					if (!in_succesful_failtest)
3802						log_error("Design elaboration failed; see full log for details\n");
3803					return;
3804				}
3805			} catch (const std::exception& e) {
3806				log_error("Exception: %s\n", e.what());
3807			}
3808	
3809			if (!settings.no_proc.value_or(false)) {
3810				// Hack to get an empty selection in a way compatible with both pre and post Yosys v0.52
3811				// Front of the selection stack should be a "full selection" at any time, and we can
3812				// amend it.
3813				RTLIL::Selection emitted_modules = design->selection_stack.front();
3814				emitted_modules.full_selection = false;
3815				for (auto name : emitted_module_names)
3816					emitted_modules.selected_modules.insert(name);
3817	
3818				design->selection_stack.push_back(emitted_modules);
3819	
3820				log_push();
3821				call(design, "proc_clean");
3822				call(design, "tribuf");
3823				call(design, "proc_rmdead");
3824				call(design, "proc_prune");
3825				call(design, "proc_init");
3826				call(design, "proc_rom");
3827				call(design, "proc_mux");
3828				call(design, "proc_clean");
3829				call(design, "opt_expr -keepdc");
3830				log_pop();
3831	
3832				design->selection_stack.pop_back();
3833			}
3834		}
3835	} SlangFrontend;
